describe('getLocaleConfig', () => {
  it('returns correct config for pt-BR', () => {
    const config = getLocaleConfig('pt-BR');
    expect(config.locale).toBe('pt-BR');
    expect(config.name).toBe('Português (Brasil)');
    expect(config.dateFormat).toBe('DD/MM/YYYY');
    expect(config.numberFormat.decimal).toBe(',');
  });

  it('returns correct config for en', () => {
    const config = getLocaleConfig('en');
    expect(config.locale).toBe('en');
    expect(config.name).toBe('English');
    expect(config.dateFormat).toBe('MM/DD/YYYY');
    expect(config.numberFormat.decimal).toBe('.');
  });

  it('returns correct config for es', () => {
    const config = getLocaleConfig('es');
    expect(config.locale).toBe('es');
    expect(config.name).toBe('Español');
    expect(config.dateFormat).toBe('DD/MM/YYYY');
  });
});

describe('getSupportedLocales', () => {
  it('returns all 3 locale configs', () => {
    const locales = getSupportedLocales();
    expect(locales).toHaveLength(3);
    expect(locales.map((l) => l.locale)).toEqual(['pt-BR', 'en', 'es']);
  });
});

// ─────────────────────────────────────────────
// formatDate
// ─────────────────────────────────────────────

describe('formatDate', () => {
  const testDate = new Date(2025, 2, 15); // March 15, 2025

  it('formats date for PT-BR (DD/MM/YYYY)', () => {
    expect(formatDate(testDate, 'pt-BR')).toBe('15/03/2025');
  });

  it('formats date for EN (MM/DD/YYYY)', () => {
    expect(formatDate(testDate, 'en')).toBe('03/15/2025');
  });

  it('formats date for ES (DD/MM/YYYY)', () => {
    expect(formatDate(testDate, 'es')).toBe('15/03/2025');
  });

  it('pads single-digit day and month', () => {
    const d = new Date(2025, 0, 5); // January 5
    expect(formatDate(d, 'pt-BR')).toBe('05/01/2025');
    expect(formatDate(d, 'en')).toBe('01/05/2025');
  });
});

// ─────────────────────────────────────────────
// formatNumber
// ─────────────────────────────────────────────

describe('formatNumber', () => {
  it('formats for PT-BR (comma decimal, dot thousands)', () => {
    expect(formatNumber(1234567, 'pt-BR')).toBe('1.234.567');
  });

  it('formats for EN (dot decimal, comma thousands)', () => {
    expect(formatNumber(1234567, 'en')).toBe('1,234,567');
  });

  it('formats for ES (comma decimal, dot thousands)', () => {
    expect(formatNumber(1234567, 'es')).toBe('1.234.567');
  });

  it('handles decimals parameter for PT-BR', () => {
    expect(formatNumber(1234.56, 'pt-BR', 2)).toBe('1.234,56');
  });

  it('handles decimals parameter for EN', () => {
    expect(formatNumber(1234.56, 'en', 2)).toBe('1,234.56');
  });

  it('formats zero correctly', () => {
    expect(formatNumber(0, 'en')).toBe('0');
    expect(formatNumber(0, 'pt-BR', 2)).toBe('0,00');
  });

  it('formats negative numbers', () => {
    expect(formatNumber(-1500, 'en')).toBe('-1,500');
    expect(formatNumber(-1500, 'pt-BR')).toBe('-1.500');
  });
});

// ─────────────────────────────────────────────
// getAllKeys
// ─────────────────────────────────────────────

describe('getAllKeys', () => {
  it('returns all keys when no namespace specified', () => {
    const keys = getAllKeys();
    expect(keys.length).toBeGreaterThan(50);
    expect(keys).toContain('common.save');
    expect(keys).toContain('auth.login');
    expect(keys).toContain('errors.generic');
  });

  it('returns only common keys when namespace specified', () => {
    const keys = getAllKeys('common');
    expect(keys.length).toBe(28); // 28 common keys
    expect(keys.every((k) => k.startsWith('common.'))).toBe(true);
  });

  it('returns only auth keys when namespace specified', () => {
    const keys = getAllKeys('auth');
    expect(keys.length).toBe(16);
    expect(keys.every((k) => k.startsWith('auth.'))).toBe(true);
  });

  it('returns keys in correct format (namespace.key)', () => {
    const keys = getAllKeys();
    for (const key of keys) {
      expect(key).toMatch(/^\w+\.\w+$/);
    }
  });
});

