// ─────────────────────────────────────────────
// Dictionaries completeness
// ─────────────────────────────────────────────

describe('dictionaries completeness', () => {
  const allNamespaces: TranslationNamespace[] = [
    'common',
    'auth',
    'dashboard',
    'editor',
    'studio',
    'settings',
    'billing',
    'errors',
  ];

  it('PT-BR dictionary has all namespaces', () => {
    for (const ns of allNamespaces) {
      expect(dictionaries['pt-BR'][ns]).toBeDefined();
    }
  });

  it('EN dictionary has all namespaces', () => {
    for (const ns of allNamespaces) {
      expect(dictionaries['en'][ns]).toBeDefined();
    }
  });

  it('ES dictionary has all namespaces', () => {
    for (const ns of allNamespaces) {
      expect(dictionaries['es'][ns]).toBeDefined();
    }
  });

  it('all namespaces have matching keys across locales', () => {
    for (const ns of allNamespaces) {
      const ptKeys = Object.keys(
        dictionaries['pt-BR'][ns] as Record<string, string>,
      ).sort();
      const enKeys = Object.keys(
        dictionaries['en'][ns] as Record<string, string>,
      ).sort();
      const esKeys = Object.keys(
        dictionaries['es'][ns] as Record<string, string>,
      ).sort();
      expect(enKeys).toEqual(ptKeys);
      expect(esKeys).toEqual(ptKeys);
    }
  });

  it('no empty strings in PT-BR dictionary', () => {
    for (const ns of allNamespaces) {
      const nsDict = dictionaries['pt-BR'][ns] as Record<string, string>;
      for (const [key, value] of Object.entries(nsDict)) {
        expect(value.length).toBeGreaterThan(0);
      }
    }
  });

  it('no empty strings in EN dictionary', () => {
    for (const ns of allNamespaces) {
      const nsDict = dictionaries['en'][ns] as Record<string, string>;
      for (const [key, value] of Object.entries(nsDict)) {
        expect(value.length).toBeGreaterThan(0);
      }
    }
  });

  it('no empty strings in ES dictionary', () => {
    for (const ns of allNamespaces) {
      const nsDict = dictionaries['es'][ns] as Record<string, string>;
      for (const [key, value] of Object.entries(nsDict)) {
        expect(value.length).toBeGreaterThan(0);
      }
    }
  });
});

// ─────────────────────────────────────────────
// useTranslation hook
// ─────────────────────────────────────────────

describe('useTranslation hook', () => {
  beforeEach(() => {
    // Clear cookies before each test
    Object.defineProperty(document, 'cookie', {
      writable: true,
      value: '',
    });
  });

  it('returns t function, locale, setLocale, and locales', () => {
    const { result } = renderHook(() => useTranslation());
    expect(typeof result.current.t).toBe('function');
    expect(typeof result.current.locale).toBe('string');
    expect(typeof result.current.setLocale).toBe('function');
    expect(Array.isArray(result.current.locales)).toBe(true);
  });

  it('defaults to pt-BR locale', () => {
    const { result } = renderHook(() => useTranslation());
    expect(result.current.locale).toBe('pt-BR');
  });

  it('t function returns correct translation', () => {
    const { result } = renderHook(() => useTranslation());
    expect(result.current.t('common.save')).toBe('Salvar');
  });

  it('setLocale changes the locale', () => {
    const { result } = renderHook(() => useTranslation());

    act(() => {
      result.current.setLocale('en');
    });

    expect(result.current.locale).toBe('en');
    expect(result.current.t('common.save')).toBe('Save');
  });

  it('t supports locale override via options', () => {
    const { result } = renderHook(() => useTranslation());
    expect(result.current.t('common.save', { locale: 'es' })).toBe('Guardar');
  });

  it('locales returns all supported locale configs', () => {
    const { result } = renderHook(() => useTranslation());
    expect(result.current.locales).toHaveLength(3);
    expect(result.current.locales[0].locale).toBe('pt-BR');
    expect(result.current.locales[1].locale).toBe('en');
    expect(result.current.locales[2].locale).toBe('es');
  });
});
